custom_css:
/* Черное небо */

/* шрифты */
@import url("https://fontsapi.zeoseven.com/437/main/result.css");
@import url("https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Russo+One&display=swap");

/* Основной текст сообщений */
body,
.mes_text,
.mes_block {
  font-family: "Huiwen-MinchoGBK", serif !important;
  font-weight: normal !important;
  font-size: 17px;
}

/* Имена, заголовки, таймер, токены */
.name_text,
.mesIDDisplay,
.mes_timer,
.tokenCounterDisplay,
.mes_reasoning_header_title::before,
.ch_name {
  font-family: "Bebas Neue", "Russo One", sans-serif !important;
  letter-spacing: 0.08em !important;
}

/* Основа - Аватар и соо */
#chat > div.mes {
  position: relative !important;
  overflow: visible !important;
  margin-top: 250px !important;
  padding: 8px 12px 10px !important;
  min-height: unset !important;
}

#chat > div.mes > div.mesAvatarWrapper {
  position: absolute !important;
  top: -238px !important;
  left: 300px !important;
  z-index: 10;
  height: auto !important;
  align-self: unset !important;
}

/* Размер аватарок */
#chat > div.mes .mesAvatarWrapper .avatar {
  width: 220px !important;
  height: 220px !important;
  border-radius: 50% !important;
}

#chat > div.mes .mesAvatarWrapper .avatar img {
  width: 100% !important;
  height: 100% !important;
  object-fit: cover;
  border-radius: 50%;
}

/* Текст */
#chat > div.mes .mes_block {
  margin-left: 0 !important;
  padding-left: 0 !important;
  width: 100% !important;
}

.mes_block .ch_name,
.mes_block .mes_text {
    width: 100%;
    box-sizing: border-box;
    margin: 0;
    padding-left: 0;
    padding-right: 0;
}

.mes_block .mes_text {
    padding-top: calc(var(--mainFontSize) * 0.8);
}

/* ПЕРВОЕ СОО */
#chat > div.mes.lastInContext {
  position: relative !important;
  overflow: visible !important;
  margin-top: 250px !important;
  padding: 8px 12px 10px !important;
}

#chat > div.mes.lastInContext > div.mesAvatarWrapper {
  position: absolute !important;
  top: -238px !important;
  left: 300px !important;
  z-index: 10;
  height: auto !important;
  align-self: unset !important;
}
/* ФОН ЗА АВАТАРОМ, ТОКЕНАМИ И ДР. */
#chat > div.mes::before {
  content: '';
  position: absolute;
  top: -280px;
  left: 12px;
  right: 12px; 
  height: 305px;

  background-image: url('https://i.postimg.cc/wvHvfj7C/IMG-8015.png');
  background-size: contain;
  background-position: center top;

  border-radius: 12px 12px 0 0;
  z-index: 5;
  pointer-events: none;
}

#chat > div.mes > div.mesAvatarWrapper {
  z-index: 10;
}


/*ФОРМАТИРОВАНИЕ*/
/*——————Стиль для текста в кавычках ""——————*/
.mes_text q {
    background: linear-gradient(135deg, rgba(230, 168, 193, 0.4), rgba(70, 70, 80, 0.4)) !important;
    padding: 2px 5px !important;
    display: inline !important;
    box-decoration-break: clone !important;
    -webkit-box-decoration-break: clone !important;
    border-left: 2px solid rgba(230, 168, 193, 0.3) !important;
    font-style: normal !important;
    color: rgba(230,168,193, 0.9) !important;
    text-shadow: 0 1px 3px rgba(0, 0, 0, 0.4) !important;
}

/*  em / курсив (*текст в звёздочках*)  */
.mes_text em,
.mes_text i {
  font-style: italic !important;
  background: linear-gradient(
    105deg,
    rgba(230, 168, 193, 0.50) 0%,
    rgba(230, 168, 193, 1)    45%,
    rgba(230, 168, 193, 0.70) 100%
  ) !important;
  -webkit-background-clip: text !important;
  background-clip: text !important;
  -webkit-text-fill-color: transparent !important;

  text-decoration: underline !important;
  text-decoration-style: dashed !important;
  text-decoration-color: rgba(230, 168, 193, 0.40) !important;
  text-underline-offset: 3px !important;
  text-decoration-thickness: 1px !important;
  filter: drop-shadow(0 0 6px rgba(230, 168, 193, 0.18)) !important;
  letter-spacing: 0.012em !important;
}

/* bold / жирный (**текст**) */
.mes_text strong,
.mes_text b {
  font-weight: 700 !important;
  font-style: normal !important;
  color: rgba(240, 210, 225, 1) !important;
  -webkit-text-fill-color: rgba(240, 210, 225, 1) !important;
}

/* ═══ Заголовки H1–H6 в сообщениях ═══ */

.mes_text h1,
.mes_text h2,
.mes_text h3,
.mes_text h4,
.mes_text h5,
.mes_text h6 {
  color: rgba(230, 168, 193, 0.95) !important;
  -webkit-text-fill-color: rgba(230, 168, 193, 0.95) !important;

  font-family: "Bebas Neue", "Russo One", sans-serif !important;
  letter-spacing: 0.08em !important;
  font-weight: normal !important;

  /* линия под заголовком */
  border-bottom: 1px dashed rgba(230, 168, 193, 0.25) !important;
  padding-bottom: 4px !important;
  margin-bottom: 8px !important;

  text-shadow: 0 0 14px rgba(230, 168, 193, 0.18) !important;
}

/* цветочек перед каждым заголовком */
.mes_text h1::before,
.mes_text h2::before,
.mes_text h3::before,
.mes_text h4::before,
.mes_text h5::before,
.mes_text h6::before {
  content: "❀ " !important;
  color: rgba(235, 177, 236, 0.75) !important;
  -webkit-text-fill-color: rgba(235, 177, 236, 0.75) !important;
  font-size: 0.85em !important;
  filter: drop-shadow(0 0 5px rgba(235, 177, 236, 0.30)) !important;
}

/* размеры по уровням */
.mes_text h1 { font-size: 1.55em !important; }
.mes_text h2 { font-size: 1.35em !important; }
.mes_text h3 { font-size: 1.18em !important; }
.mes_text h4 { font-size: 1.05em !important; }
.mes_text h5,
.mes_text h6 { font-size: 0.95em !important; opacity: 0.85 !important; }


/* призрак */
i.mes_ghost.fa-solid.fa-ghost::before {
color: rgba(230, 168, 193, 0.7) !important;
}

/* сендбар */
#send_textarea::placeholder {
    color: transparent !important;
    opacity: 0 !important;
}
#form_sheld {
  margin: 0 auto !important;
}

#sheld {
  top: var(--bottomFormBlockSize);
  height: calc(100dvh - var(--bottomFormBlockSize));
  max-height: calc(100dvh - var(--bottomFormBlockSize));
  min-height: calc(100dvh - var(--bottomFormBlockSize)); 
}

#send_textarea,
#send_form textarea#send_textarea {
  font-family: "Huiwen-MinchoGBK", serif !important;
  font-size: 16px !important;        
  line-height: 1.55 !important;
  color: #C6C6BE !important;

  background: rgba(17, 18, 18, 0.75) !important;
  border: 1px solid rgba(230, 168, 193, 0.35) !important;
  border-radius: 14px !important;

  padding: 4px 7px !important;
  box-shadow:
    inset 0 1px 6px rgba(0,0,0,0.55),
    0 0 10px rgba(230, 168, 193, 0.10) !important;

  caret-color: rgba(230, 168, 193, 0.95) !important
}

#send_textarea::placeholder {
  color: rgba(198, 198, 190, 0.45) !important;
}
#send_form{
  position: relative !important;
  padding-top: 6px !important; /* место под линию */
}

#send_form::before{
  content: "" !important;
  position: absolute !important;
  left: 12px !important;
  right: 12px !important;
  top: 4px !important;
  height: 1px !important;

  background: repeating-linear-gradient(
    to right,
    rgba(230,168,193,0.9) 0px,
    rgba(230,168,193,0.55) 6px,
    transparent 6px,
    transparent 12px
  ) !important;

  opacity: 0.65 !important;
  pointer-events: none !important;
}

#send_form {
  border-radius: 16px !important;
  overflow: hidden !important;
  background: rgba(17, 18, 18, 0.65) !important;
  border: 1px solid rgba(230,168,193,0.25) !important;
}

/* Иконки кнопок */
#options_button::before {
  content: '❀' !important;
  font-size: 26px !important;
  color: rgba(230, 168, 193, 0.9) !important;
}

#extensionsMenuButton::before {
  content: '❀' !important;
  font-size: 26px !important;
  color: rgba(230, 168, 193, 0.9) !important;
}

#send_but::before {
  content: '➤' !important;
  font-size: 20px !important;
  color: rgba(230, 168, 193, 1) !important;
}
#mes_stop i.fa-circle-stop {
  font-size: 0 !important;
  color: transparent !important;
}

#mes_stop i.fa-circle-stop::before {
  content: '❀' !important;
  font-family: inherit !important;
  font-size: 26px !important;
  color: rgba(230, 168, 193, 1) !important;
  font-style: normal !important;
}

/* ===== quickPersonaCaret: розовый под тему ===== */

