  letter-spacing: 0.08em !important;
  z-index: 6;
  pointer-events: none !important;
}
#chat > div.mes > div.mesAvatarWrapper > div.mes_timer,
#chat > div.mes > div.mesAvatarWrapper > div.tokenCounterDisplay {
  position: absolute !important;
