/*  Токены — после таймера  */
#chat > div.mes > div.mesAvatarWrapper > div.tokenCounterDisplay {
  left: -88px !important;
}

/* Скрываем таймер если он пустой */
#chat > div.mes > div.mesAvatarWrapper > div.mes_timer:empty {
  display: none !important;
}

/* Если таймера нет — токены сдвигаются на его место */
#chat > div.mes > div.mesAvatarWrapper > div.mes_timer:empty 
  ~ div.tokenCounterDisplay {
  left: -140px !important;  /* = left таймера */
}

/* топбар */
